pin_message_infotext = TextObject(bs_BA="Unesite 4-znamenkasti PIN radionice kako biste resetovali poruku\nupozorenja.", cs_CZ="Pro vyresetování varovného hlášení zadejte prosím 4místný servisní PIN.", da_DK="Angiv firecifret værkstedspinkode for at nulstille advarslen.", de_DE="Bitte gib die 4-stellige Werkstatt-PIN ein, um die Warnmeldung\nzurückzusetzen.", el_GR="Καταχωρίστε το 4-ψήφιο PIN συνεργείου., για να επαναφέρετε (reset)\nτο προειδοποιητικό μήνυμα.", en_GB="Please enter the 4-digit workshop PIN to reset the warning message.", es_ES="Por favor, introduzca el PIN por defecto de 4 dígitos para restablecer\nel mensaje de aviso.", fi_FI="Syötä 4-merkkinen korjaamo-PIN-koodi nollataksesi varoituksen.", fr_FR="Veuillez entrer le code PIN à 4 chiffres de l'atelier pour réinitialiser\nle message d'alerte.", hr_HR="Unesite 4-znamenkasti PIN radionice kako biste poništili\nupozoravajuću obavijest.", hu_HU="A figyelmeztető üzenet visszaállításához add meg a 4 jegyű szerviz\nPIN-kódot.", it_IT="Immettere il PIN d'officina a 4 cifre per azzerare il messaggio di\navvertimento.", nl_NL="Voer een 4-cijferige werkplaatspincode in om de waarschuwingsmelding\nte verwijderen.", no_NO="Legg inn den 4-sifrede verksted-PIN-koden for å tilbakestille advarselen.", pl_PL="Wprowadź 4-cyfrowy kod PIN serwisu, aby skasować komunikat\nostrzegawczy.", pt_PT="Por favor, introduz o PIN da oficina de 4 dígitos para eliminar a\nnotificação de advertência.", ro_RO="Introduceţi codul PIN pentru atelier cu 4 poziţii, pentru a reseta\nmesajul de avertizare.", ru_RU="Введите 4-значный PIN-код автосервиса, чтобы сбросить\nпредупреждение.", sk_SK="Prosím, zadajte 4-miestny PIN dielne, aby ste zresetovali varovné\nhlásenie.", sl_SI="Za resetiranje opozorila vnesite 4-mestno servisno PIN-kodo.", sr_RS="Unesite 4-cifreni PIN radionice da biste resetovali poruku upozorenja.", sv_SE="Ange den 4-siffriga verkstads-PIN-koden för att återställa\nvarningsmeddelandet.", tr_TR="Lütfen uyarı mesajını sıfırlamak için, 4 haneli atölye PIN'ini gir.", uk_UA="Введіть 4-значний заводський PIN-код, щоб скинути попередження.")
pin_reset_sent_toast = TextObject(bs_BA="Davanje naloga za resetovanje u toku.", cs_CZ="Resetování se spustí.", da_DK="Nulstilling igangsættes.", de_DE="Rücksetzung wird veranlasst.", el_GR="Θα δρομολογηθεί επαναφορά (reset).", en_GB="Resetting…", es_ES="Habilitando restablecimiento.", fi_FI="Nollaus suoritetaan.", fr_FR="Lancement de la réinitialisation en cours.", hr_HR="Poništavanje se inicira.", hu_HU="A visszaállítás elindításra kerül.", it_IT="Viene avviato l'azzeramento.", nl_NL="Verwijdering wordt in gang gezet.", no_NO="Starter tilbakestilling.", pl_PL="Kasowanie jest inicjowane.", pt_PT="Eliminação será permitida.", ro_RO="Se iniţiază resetarea.", ru_RU="Начинается сброс.", sk_SK="Reset sa vyvolá.", sl_SI="Začetek resetiranja.", sr_RS="Davanje naloga za resetovanje je u toku.", sv_SE="Återställningen inleds.", tr_TR="Sıfırlama başlatılıyor.", uk_UA="Починається скидання.")
